Find the bug(s) in the following code and explain the fix:

```javascript
function binarySearch(arr, target) {
  let left = 0
  let right = arr.length - 1

  while (left < right) {
    const mid = Math.floor((left + right) / 2)

    if (arr[mid] === target) {
      return mid
    } else if (arr[mid] < target) {
      left = mid + 1
    } else {
      right = mid - 1
    }
  }

  return -1
}

// Test cases:
console.log(binarySearch([1, 3, 5, 7, 9], 5))  // Expected: 2, Actual: 2 ✓
console.log(binarySearch([1, 3, 5, 7, 9], 9))  // Expected: 4, Actual: -1 ✗
console.log(binarySearch([1, 3, 5, 7, 9], 1))  // Expected: 0, Actual: 0 ✓
console.log(binarySearch([1], 1))               // Expected: 0, Actual: -1 ✗
```
